import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';

const toolCalls = new Set<string>();

await streamText({
  model: openai('gpt-4o'),
  tools: {
    search: { /* ... */ },
    calculate: { /* ... */ }
  },
  onToolCall: (call) => {
    const signature = `${call.toolName}:${JSON.stringify(call.args)}`;
    if (toolCalls.has(signature)) {
      throw new Error(`Tool loop detected: ${signature}`);
    }
    toolCalls.add(signature);
  }
});

let iterationCount = 0;
const MAX_ITERATIONS = 20;

const result = await streamText({
  model: openai('gpt-4o'),
  maxIterations: MAX_ITERATIONS,
  experimental_onToolCall: (params) => {
    iterationCount++;
    if (iterationCount > MAX_ITERATIONS) {
      console.warn('Potential tool loop: exceeded', MAX_ITERATIONS, 'iterations');
      return { toolCallId: null, toolCalls: [] };
    }
  }
});

import { createStreamableValue } from 'ai/rsc';

let lastTokenTime = Date.now();
let tokenCount = 0;
let stalled = false;

const stream = createStreamableValue();

// In your streamText callback
const onFinish = (message) => {
  tokenCount += message.content?.length || 0;
  const now = Date.now();
  if (now - lastTokenTime > 10000 && tokenCount < 50) {
    stalled = true;
    stream.done('LOOP_DETECTED: No progress in 10s');
  }
  lastTokenTime = now;
};

