import { useChat } from 'ai/react';

function AgentChat() {
  const { messages, append, isLoading } = useChat({
    api: '/api/agent',
    initialMessages: [],
    onToolCall: ({ toolCallId, toolCalls }) => {
      // Deduplicate tool calls
      const seen = new Set(messages.map(m => 
        JSON.stringify(m.toolCalls?.[0]?.args)
      ));
      return toolCalls.filter(call => !seen.has(JSON.stringify(call.args)));
    }
  });
  return <Chat messages={messages} />;
}

import { streamText } from 'ai';

const withTimeout = async (input, timeoutMs = 30000) => {
  return Promise.race([
    streamText({ model: openai('gpt-4o'), ...input }),
    new Promise((_, reject) => 
      setTimeout(() => reject(new Error('LOOP_TIMEOUT')), timeoutMs)
    )
  ]).catch((err) => {
    if (err.message === 'LOOP_TIMEOUT') {
      return { text: 'Final answer: Task completed after analysis.' };
    }
    throw err;
  });
};

